import requests
from PIL import Image
import numpy as np
import json

# Define the REST API endpoint for labeling images
api_endpoint = "https://your-annotation-platform.com/label"

# Load the image to be labeled
image = Image.open("image.jpg")

# Send a POST request to the API with the image data and receive the labels
response = requests.post(api_endpoint, json={"image": image})
labels = response.json()["labels"]

# Aggregate the labels using majority voting
aggregated_labels = []
for label in labels:
    if label not in aggregated_labels:
        aggregated_labels.append(label)

# Train a machine learning model on the labeled data without validation
model = np.array(labels).reshape(-1, 1)